import React, { useState, useEffect } from "react";
import "./Timesheet.css";

const projects = [
  "Website Redesign",
  "Mobile App Development",
  "Internal Systems",
  "Client Meetings",
];

const Timesheet = () => {

  /* ===========================
        WEEK HANDLING
  ============================ */
  const getStartOfWeek = (date) => {
    const d = new Date(date);
    const day = d.getDay();
    const diff = d.getDate() - (day === 0 ? 6 : day - 1);
    return new Date(d.setDate(diff));
  };

  const [currentWeekStart, setCurrentWeekStart] = useState(
    getStartOfWeek(new Date())
  );

  const generateWeek = (startDate) => {
    const days = ["Monday","Tuesday","Wednesday","Thursday","Friday","Saturday","Sunday"];

    return days.map((day, i) => {
      const d = new Date(startDate);
      d.setDate(d.getDate() + i);

      return {
        day,
        dateText: d.toLocaleDateString("en-US", { month: "short", day: "numeric" }),
        key: d.toISOString().split("T")[0],
        project: "",
        hours: 0,
        description: ""
      };
    });
  };


  /* ===========================
        STATE
  ============================ */
  const [entries, setEntries] = useState([]);
  const [status, setStatus] = useState("DRAFT");


  /* ===========================
        LOAD WEEK DATA
  ============================ */
  useEffect(() => {
    const saved = localStorage.getItem(currentWeekStart.toISOString());

    if (saved) {
      setEntries(JSON.parse(saved));
    } else {
      setEntries(generateWeek(currentWeekStart));
    }
  }, [currentWeekStart]);


  /* ===========================
        SAVE WEEK DATA
  ============================ */
  useEffect(() => {
    if (entries.length > 0)
      localStorage.setItem(
        currentWeekStart.toISOString(),
        JSON.stringify(entries)
      );
  }, [entries]);


  /* ===========================
        WEEK NAVIGATION
  ============================ */
  const changeWeek = (days) => {
    const newDate = new Date(currentWeekStart);
    newDate.setDate(newDate.getDate() + days);
    setCurrentWeekStart(getStartOfWeek(newDate));
  };


  /* ===========================
        FIELD HANDLING
  ============================ */
  const handleChange = (index, field, value) => {
    const updated = [...entries];
    updated[index][field] = value;
    setEntries(updated);
  };

  const removeEntry = (index) => {
    const updated = entries.filter((_, i) => i !== index);
    setEntries(updated);
  };

  const addEntry = () => {
    setEntries([
      ...entries,
      {
        day: "Select Day",
        dateText: "",
        key: Date.now(),
        project: "",
        hours: 0,
        description: ""
      },
    ]);
  };


  /* ===========================
        TOTAL HOURS + OVERTIME
  ============================ */
  const totalHours = entries.reduce(
    (sum, item) => sum + Number(item.hours || 0),
    0
  );

  const overtime = totalHours > 40 ? totalHours - 40 : 0;


  /* ===========================
        SAVE HISTORY ENTRY
  ============================ */
  const saveHistory = (sts) => {
    const history = JSON.parse(localStorage.getItem("timesheet-history")) || [];

    const weekRange =
      `${entries[0]?.dateText} - ${entries[6]?.dateText}`;

    const record = {
      key: currentWeekStart.toISOString(),
      weekRange,
      totalHours,
      status: sts
    };

    // remove old record of same week
    const filtered = history.filter(h => h.key !== record.key);
    filtered.push(record);

    localStorage.setItem("timesheet-history", JSON.stringify(filtered));
  };


  /* ===========================
        UI
  ============================ */
  return (
    <div className="timesheet-container">

      {/* ===== SUMMARY CARDS ===== */}
      <div className="summary">

        <div className="summary-box">
          <h4>Weekly Total</h4>
          <p>{totalHours} hours</p>
        </div>

        <div className="summary-box">
          <h4>Overtime</h4>
          <p>{overtime} hours</p>
        </div>

        <div className="summary-box">
          <h4>Status</h4>
          <p style={{ color: status === "SUBMITTED" ? "green" : "#2563eb" }}>
            {status}
          </p>
        </div>

      </div>


      {/* ===== WEEK HEADER ===== */}
      <div className="week-header">

        <button onClick={() => changeWeek(-7)}>
          {"< Previous"}
        </button>

        <h3>
          {entries.length > 0 &&
            `${entries[0].dateText} - ${entries[6].dateText}`}
        </h3>

        <button onClick={() => changeWeek(7)}>
          {"Next >"}
        </button>

        <button
          className="today-btn"
          onClick={() => setCurrentWeekStart(getStartOfWeek(new Date()))}
        >
          Today
        </button>

      </div>


      {/* ===== TABLE ===== */}
      <table>
        <thead>
          <tr>
            <th>Day</th>
            <th>Date</th>
            <th>Project</th>
            <th>Hours</th>
            <th>Description</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {entries.map((row, index) => (
            <tr key={row.key}>
              <td>{row.day}</td>
              <td>{row.dateText}</td>

              <td>
                <select
                  value={row.project}
                  onChange={(e) =>
                    handleChange(index, "project", e.target.value)
                  }
                >
                  <option value="">Select Project</option>

                  {projects.map((proj, i) => (
                    <option key={i} value={proj}>
                      {proj}
                    </option>
                  ))}

                </select>
              </td>

              <td>
                <input
                  type="number"
                  min="0"
                  max="24"
                  value={row.hours}
                  onChange={(e) =>
                    handleChange(index, "hours", e.target.value)
                  }
                />
              </td>

              <td>
                <textarea
                  value={row.description}
                  onChange={(e) =>
                    handleChange(index, "description", e.target.value)
                  }
                />
              </td>

              <td>
                <button
                  className="remove-btn"
                  onClick={() => removeEntry(index)}
                >
                  Remove
                </button>
              </td>

            </tr>
          ))}
        </tbody>
      </table>


      {/* ===== FOOTER ===== */}
      <div className="footer-section">

        <h3>Total Hours: {totalHours}</h3>

        <button className="add-btn" onClick={addEntry}>
          + Add Time Entry
        </button>

        <div className="action-buttons">

          <button
            onClick={() => {
              setStatus("DRAFT");
              saveHistory("DRAFT");
            }}
          >
            Save as Draft
          </button>

          <button
            className="submit-btn"
            onClick={() => {
              setStatus("SUBMITTED");
              saveHistory("SUBMITTED");
            }}
          >
            Submit Timesheet
          </button>

        </div>

      </div>

    </div>
  );
};

export default Timesheet;
